INSERT IGNORE INTO `artistes` (`id`, `nom`, `prenom`, `nationalite`, `biographie`, `date_naissance`, `date_deces`) VALUES
(1, 'Warhol', 'Andy', 'Américain', 'Andy Warhol est la figure centrale du Pop Art américain. Ancien directeur artistique publicitaire devenu peintre, il transforme les icônes de la culture de masse — boîtes de soupe, stars de cinéma, billets de dollars — en œuvres sérigraphiées reproduites à l\'infini. Son atelier new-yorkais, la Factory, devient un laboratoire créatif mêlant peinture, cinéma expérimental et musique. Par son effacement de la frontière entre art et commerce, il redéfinit durablement le statut de l\'objet artistique et la notion d\'auteur.', '1928', '1987'),
(2, 'Böcklin', 'Arnold', 'Suisse', 'Arnold Böcklin est l\'un des peintres symbolistes les plus influents du XIXe siècle. Formé à Düsseldorf puis installé longuement en Italie, il développe un univers de mythologie nordique et méditerranéenne mêlée, peuplé de créatures fantastiques, de paysages oniriques et de figures allégoriques. Son œuvre, à la frontière du réalisme et du fantastique, a profondément marqué le Jugendstil allemand, le surréalisme naissant et la culture visuelle fin-de-siècle européenne.', '1827', '1901'),
(3, 'Schwabe', 'Carlos', 'Suisse-Allemand', 'Carlos Schwabe est un peintre et illustrateur suisse d\'origine allemande, figure majeure du symbolisme fin-de-siècle. Établi à Paris, il se distingue par ses illustrations pour les Fleurs du mal de Baudelaire et ses toiles à l\'iconographie mélancolique et spirituelle, mêlant influences de l\'Art nouveau et du préraphaélisme. Son goût pour les sujets funèbres, l\'angélologie et la beauté idéalisée en fait l\'un des représentants les plus singuliers du symbolisme européen.', '1866', '1926'),
(4, 'Friedrich', 'Caspar David', 'Allemand', 'Caspar David Friedrich est le plus grand représentant du romantisme allemand en peinture. Ses paysages — forêts brumeuses, ruines gothiques, couchers de soleil sur la mer — ne sont jamais de simples descriptions de la nature mais des méditations sur l\'infini, la solitude et la condition humaine face au sublime. Sa figure récurrente de dos, contemplant l\'immensité, invite le spectateur à une expérience intérieure que le peintre liait à une forme de spiritualité panthéiste.', '1774', '1840'),
(5, 'Monet', 'Claude', 'Français', 'Claude Monet est le père de l\'impressionnisme et l\'un des peintres les plus influents de l\'histoire de l\'art occidental. Obsédé par la lumière changeante et les effets atmosphériques, il invente une peinture de la sensation fugitive, travaillant en plein air et multipliant les séries sur un même motif — meules, cathédrale de Rouen, nymphéas. Son jardin de Giverny, qu\'il conçoit comme une œuvre totale, lui inspire les grandes décorations de nénuphars conservées à l\'Orangerie de Paris.', '1840', '1926'),
(6, 'Velázquez', 'Diego', 'Espagnol', 'Diego Velázquez est le plus grand peintre de l\'âge d\'or espagnol et l\'un des maîtres absolus de la peinture occidentale. Peintre officiel du roi Philippe IV, il domine la cour de Madrid pendant trois décennies et révolutionne le portrait royal, le tableau de genre et la composition. Sa touche libre, sa maîtrise de l\'atmosphère et sa capacité à capturer la psychologie des personnages préfigurent l\'impressionnisme et influenceront Manet, Sargent et Picasso.', '1599', '1660'),
(7, 'Manet', 'Édouard', 'Français', 'Édouard Manet est la figure charnière entre la peinture académique et la modernité impressionniste. Sans jamais exposer avec le groupe impressionniste, il en inspire les membres par ses sujets contemporains, son refus du récit académique et sa touche large et directe. Ses toiles scandaleuses — Olympia, Le Déjeuner sur l\'herbe — bouleversent les conventions du nu et du sujet historique, en imposant la réalité présente comme seul sujet légitime de la peinture moderne.', '1832', '1883'),
(8, 'Munch', 'Edvard', 'Norvégien', 'Edvard Munch est le père fondateur de l\'expressionnisme européen. Marqué par des deuils précoces et une santé mentale fragile, il développe une œuvre qui fait de l\'angoisse, de la jalousie, de la mort et du désir les sujets centraux de la peinture. Ses toiles aux couleurs violentes et aux formes déformées exercent une influence directe sur les expressionnistes allemands du Brücke et du Blaue Reiter. Le Cri, image universelle de la détresse moderne, reste son œuvre la plus connue.', '1863', '1944'),
(9, 'Hopper', 'Edward', 'Américain', 'Edward Hopper est le peintre emblématique de la solitude américaine moderne. Ses scènes de cafés déserts, de chambres d\'hôtel, de stations-service isolées et de façades urbaines nocturnes capturent avec une intensité silencieuse l\'aliénation de l\'individu dans la société de masse. Sa lumière tranchante, empruntée à Vermeer et à Hogarth, transforme les intérieurs banals en espaces chargés d\'une tension psychologique retenue. Son influence sur le cinéma américain — de Hitchcock aux néo-noirs — est considérable.', '1882', '1967'),
(10, 'Delacroix', 'Eugène', 'Français', 'Eugène Delacroix est le chef de file du romantisme français et l\'adversaire pictural d\'Ingres dans le grand débat entre couleur et dessin qui structure la peinture du XIXe siècle. Nourri par les maîtres vénitiens, Rubens et ses voyages au Maroc, il développe une peinture vibrante, dramatique et coloriste. Son journal intime et ses écrits théoriques font de lui un penseur majeur de l\'esthétique romantique, admiré par Baudelaire qui en fait le peintre de la modernité.', '1798', '1863'),
(11, 'Goya', 'Francisco de', 'Espagnol', 'Francisco de Goya est l\'un des peintres les plus complexes et les plus modernes de toute l\'histoire de l\'art occidental. D\'abord peintre de cour brillant et officiel, il bascule après sa surdité et les guerres napoléoniennes vers une œuvre sombre et visionnaire — les Désastres de la guerre, les Peintures noires — qui anticipe l\'expressionnisme et le surréalisme. Témoin des violences de son temps, il en fait une peinture sans concession ni héroïsme.', '1746', '1828'),
(12, 'Marc', 'Franz', 'Allemand', 'Franz Marc est l\'un des fondateurs du Blaue Reiter (Le Cavalier bleu), mouvement expressionniste allemand co-créé avec Wassily Kandinsky en 1911. Sa peinture, caractérisée par des animaux aux couleurs symboliques dans des paysages éclatés par le prisme cubiste, cherche à exprimer la pureté spirituelle de la nature contre la corruption du monde humain. Mort au front de Verdun à trente-six ans, il laisse une œuvre brève mais fondamentale dans l\'histoire de l\'expressionnisme européen.', '1880', '1916'),
(13, 'Panini', 'Giovanni Paolo', 'Italien', 'Giovanni Paolo Panini est le maître incontesté du capriccio architectural et de la peinture de ruines antiques au XVIIIe siècle. Installé à Rome, il devient le peintre attitré des voyageurs du Grand Tour européen en leur fournissant des vues idéalisées de la Rome antique et baroque. Ses vastes compositions intérieures — galeries imaginaires remplies de statues et de tableaux célèbres — anticipent les musées encyclopédiques et témoignent de la fascination des Lumières pour la mémoire de l\'Antiquité.', '1691', '1765'),
(14, 'Wood', 'Grant', 'Américain', 'Grant Wood est la figure centrale du régionalisme américain, mouvement des années 1930 qui célèbre les paysages et la culture rurale du Midwest américain en réaction au cosmopolitisme des avant-gardes européennes. Formé en Europe, notamment en Allemagne, il adopte à son retour une technique minutieuse inspirée des maîtres flamands. American Gothic, son œuvre la plus connue, est devenu l\'une des images les plus reproductibles de la culture américaine, oscillant entre hommage, parodie et commentaire social.', '1891', '1942'),
(15, 'Klimt', 'Gustav', 'Autrichien', 'Gustav Klimt est le fondateur et la figure tutélaire de la Sécession viennoise, mouvement de rupture avec l\'académisme autrichien fondé en 1897. Sa peinture, caractérisée par l\'usage décoratif de l\'or et des métaux précieux, l\'ornementation byzantine et la représentation frontale du désir érotique, constitue l\'un des sommets de l\'Art nouveau européen. Ses grandes allégories — La Frise Beethoven, Le Baiser, Judith — synthétisent philosophie nietzschéenne, symbolisme et raffinement décoratif.', '1862', '1918'),
(16, 'Caillebotte', 'Gustave', 'Français', 'Gustave Caillebotte est l\'un des membres les plus originaux du groupe impressionniste, longtemps sous-estimé parce que riche mécène des autres membres du groupe. Sa peinture se distingue par une perspective plongeante et des cadrages photographiques qui lui sont propres, associant rigueur réaliste et sensibilité impressionniste. Ses scènes parisiennes — rues sous la pluie, raboteurs de parquet, balcons haussmanniens — offrent l\'un des documents les plus précis et les plus beaux de la transformation de Paris au XIXe siècle.', '1848', '1894'),
(17, 'Vettriano', 'Jack', 'Écossais', 'Jack Vettriano est un peintre écossais autodidacte, né Jack Hoggan, dont la notoriété populaire est inversement proportionnelle à la reconnaissance critique. Ses scènes élégantes de couples dans des décors rétro des années 1940-1950, baignées d\'une lumière mélancolique et d\'une atmosphère de film noir, ont conquis un public immense au Royaume-Uni. The Singing Butler, son tableau le plus célèbre, est l\'une des images les plus reproduites de la peinture britannique contemporaine, malgré le mépris persistant d\'une partie du monde de l\'art officiel.', '1951', ''),
(18, 'David', 'Jacques-Louis', 'Français', 'Jacques-Louis David est le peintre officiel de la Révolution française et du Premier Empire, et le maître incontesté du néoclassicisme. Formé à Rome où il redécouvre l\'Antiquité grecque et romaine, il en fait le répertoire formel et moral d\'une peinture politique engagée. Sa collaboration avec Robespierre puis Napoléon fait de lui le premier artiste à assumer pleinement un rôle de propagandiste d\'État. Sa longue carrière traverse toutes les convulsions de l\'histoire française et forge l\'image visuelle de la République et de l\'Empire.', '1748', '1825'),
(19, 'Eyck', 'Jan van', 'Flamand', 'Jan van Eyck est l\'un des plus grands peintres de toute l\'histoire de l\'art occidental et le maître de la peinture flamande du XVe siècle. Longtemps crédité de l\'invention de la peinture à l\'huile — dont il est en tout cas le perfectionniste absolu — il révolutionne la représentation du monde visible par un rendu des matières, des reflets et de la lumière d\'une précision inégalée. Peintre de cour de Philippe le Bon, duc de Bourgogne, il représente l\'apogée de la civilisation flamande médiévale.', 'vers 1390', '1441'),
(20, 'Bosch', 'Jérôme', 'Néerlandais', 'Jérôme Bosch — Hieronymus Bosch de son vrai nom — est l\'un des artistes les plus énigmatiques de toute l\'histoire de l\'art. Peintre de la ville de Bois-le-Duc, il développe un univers fantastique et moralisateur peuplé de créatures hybrides, de visions infernales et de scènes d\'une étrangeté radicale, sans équivalent dans la peinture de son temps. Ses triptyques — le Jardin des délices, le Chariot de foin, la Tentation de saint Antoine — fascinent autant aujourd\'hui qu\'au XVIe siècle, résistant à toute interprétation définitive.', 'vers 1450', '1516'),
(21, 'Jongkind', 'Johan Barthold', 'Néerlandais-Français', 'Johan Barthold Jongkind est un peintre et aquarelliste néerlando-français considéré comme l\'un des précurseurs directs de l\'impressionnisme. Installé en France, il développe une technique de plein air fondée sur la rapidité d\'exécution, la sensibilité aux effets de lumière et une palette claire qui annoncent la révolution impressionniste. Monet, qui le rencontre à Honfleur dans les années 1860, le reconnaît comme l\'un de ses maîtres déterminants. Son œuvre graphique, notamment ses eaux-fortes, est particulièrement estimée.', '1819', '1891'),
(22, 'Vermeer', 'Johannes', 'Néerlandais', 'Johannes Vermeer est l\'un des plus grands maîtres de la peinture hollandaise du XVIIe siècle, dont l\'œuvre réduite — une quarantaine de tableaux — atteint une perfection technique et une profondeur silencieuse inégalées. Ses intérieurs baignés de lumière latérale, ses personnages saisis dans des gestes ordinaires — lire une lettre, verser du lait, jouer d\'un instrument — constituent des instants de grâce immobile. La précision optique de sa peinture a conduit certains chercheurs à avancer qu\'il utilisait une chambre obscure.', '1632', '1675'),
(23, 'Turner', 'Joseph Mallord William', 'Britannique', 'J.M.W. Turner est le plus grand peintre britannique de l\'histoire et l\'un des révolutionnaires absolus de la peinture de paysage. Parti d\'une maîtrise classique héritée de Claude Lorrain, il pousse progressivement la lumière et la couleur vers une dissolution des formes qui préfigure directement l\'impressionnisme et l\'abstraction. Ses tempêtes marines, ses paysages alpestres et ses embrasements de lumière font de lui le peintre du sublime romantique par excellence. Monet, de passage à Londres, sera directement marqué par ses œuvres.', '1775', '1851'),
(24, 'Hokusai', 'Katsushika', 'Japonais', 'Katsushika Hokusai est le maître de l\'estampe japonaise ukiyo-e et l\'artiste japonais le plus universellement connu en Occident. Auteur d\'une œuvre colossale — plus de trente mille estampes, dessins et peintures — il ne cesse de se réinventer tout au long de sa très longue carrière. Ses Trente-six vues du mont Fuji, et en particulier La Grande Vague de Kanagawa, ont exercé une fascination déterminante sur les artistes européens du japonisme, influençant directement Monet, Van Gogh, Degas et l\'Art nouveau.', '1760', '1849'),
(25, 'Vinci', 'Léonard de', 'Italien', 'Léonard de Vinci est l\'archétype de l\'homme de la Renaissance — peintre, sculpteur, architecte, ingénieur, anatomiste, musicien et philosophe. Sa peinture, en un nombre d\'œuvres intentionnellement limité, atteint un sommet de perfection technique avec l\'invention du sfumato, cette technique de transitions imperceptibles entre lumière et ombre qui donne à ses figures une présence et une profondeur psychologique sans précédent. La Joconde et La Cène sont ses deux œuvres les plus célèbres et les plus étudiées de l\'histoire de l\'art.', '1452', '1519'),
(26, 'Michel-Ange', '', 'Italien', 'Michel-Ange di Lodovico Buonarroti Simoni est l\'une des figures les plus extraordinaires de toute l\'histoire de l\'art occidental — sculpteur, peintre, architecte et poète d\'une puissance créatrice sans égale. Ses sculptures — le David, la Pietà, Moïse — et ses fresques de la chapelle Sixtine définissent les canons de la représentation du corps humain dans la grande tradition occidentale. Sa vie entière, de Florence à Rome, est placée sous le signe de la rivalité et de la grandeur, au service des plus grands mécènes de son temps.', '1475', '1564'),
(27, 'Picasso', 'Pablo', 'Espagnol', 'Pablo Picasso est le peintre le plus influent du XXe siècle et l\'une des personnalités artistiques les plus prolifiques de l\'histoire. Co-fondateur du cubisme avec Georges Braque, il révolutionne la représentation en fragmentant les formes et en montrant simultanément plusieurs points de vue. Son œuvre traverse de multiples périodes — bleue, rose, cubiste, néoclassique, surréaliste — sans jamais s\'enfermer dans un style. Artiste politique engagé, il laisse dans Guernica le manifeste anti-guerre le plus puissant du XXe siècle.', '1881', '1973'),
(28, 'Renoir', 'Pierre-Auguste', 'Français', 'Pierre-Auguste Renoir est l\'un des principaux membres du groupe impressionniste et le peintre de la joie de vivre par excellence. Ses tableaux — scènes de plein air, bal populaire, baigneurs, portraits de femmes et d\'enfants — célèbrent la lumière, la chaleur humaine et les plaisirs simples de la société française de la Troisième République. Dans la dernière partie de sa vie, touché par un rhumatisme déformant, il poursuit sa peinture en attachant les pinceaux à ses mains, refusant toute capitulation devant la douleur.', '1841', '1919'),
(29, 'Rijn', 'Rembrandt van', 'Néerlandais', 'Rembrandt van Rijn est universellement considéré comme le plus grand peintre du Siècle d\'or néerlandais et l\'un des maîtres absolus de la peinture occidentale. Graveur, dessinateur et peintre d\'une fécondité prodigieuse, il révolutionne le portrait, la scène historique et le paysage par son usage dramatique du clair-obscur, hérité du caravagisme mais poussé bien plus loin. Sa série d\'autoportraits — plus de quatre-vingt peintures, dessins et gravures — constitue l\'une des plus grandes introspections visuelles de l\'histoire de l\'art.', '1606', '1669'),
(30, 'Magritte', 'René', 'Belge', 'René Magritte est le plus grand représentant du surréalisme belge et l\'un des peintres les plus philosophiquement profonds du XXe siècle. À la différence des surréalistes français, son travail n\'explore pas le rêve ou l\'inconscient freudien mais le langage et les rapports entre les mots, les images et les choses. Ses toiles — la trahison des images, les amants, le fils de l\'homme — posent des questions radicales sur la représentation, l\'identité et la réalité, peintes dans un style délibérément banal qui renforce l\'étrangeté du contenu.', '1898', '1967'),
(31, 'Dalí', 'Salvador', 'Espagnol', 'Salvador Dalí est la figure la plus flamboyante et la plus médiatisée du surréalisme. Exclu du groupe par André Breton pour ses provocations politiques, il poursuit une carrière solitaire dans laquelle il développe sa méthode paranoïaque-critique — projection d\'images hallucinées dans des paysages peints avec une précision photographique. Personnage public extravagant autant qu\'artiste sérieux, il s\'impose comme l\'un des peintres les plus reconnaissables du XXe siècle, fasciné par la science, la psychanalyse, la religion et la mort.', '1904', '1989'),
(32, 'Botticelli', 'Sandro', 'Italien', 'Sandro Botticelli est le peintre le plus représentatif de la Renaissance florentine médicéenne, dont il incarne la synthèse entre culture humaniste, néoplatonisme et raffinement formel. Ses grandes toiles mythologiques — La Naissance de Vénus, Le Printemps — commandées par Laurent de Médicis, définissent l\'iconographie de la beauté idéale de la Renaissance. Sur le tard, touché par les prédications de Savonarole, il se tourne vers une peinture religieuse plus austère. Son œuvre, longtemps oubliée, est redécouverte et portée aux nues par les préraphaélites au XIXe siècle.', '1445', '1510'),
(33, 'Géricault', 'Théodore', 'Français', 'Théodore Géricault est la figure fondatrice du romantisme français en peinture, mort à trente-deux ans dans un accident de cheval, laissant une œuvre brève mais révolutionnaire. Son Radeau de la Méduse, par son réalisme brutal, son sujet d\'actualité politique et sa composition anti-héroïque, brise avec l\'idéalisme néoclassique de David et annonce la sensibilité romantique. Ses portraits de fous, réalisés en collaboration avec le médecin Esquirol, constituent l\'un des premiers exemples d\'une peinture clinique du visage humain.', '1791', '1824'),
(34, 'Gogh', 'Vincent van', 'Néerlandais', 'Vincent van Gogh est l\'un des peintres les plus célèbres et les plus aimés de l\'histoire de l\'art, dont la vie tragique et l\'œuvre flamboyante sont indissociables dans l\'imaginaire collectif. Autodidacte entré en peinture tardivement, il développe en une décennie une œuvre d\'une intensité émotionnelle et d\'une originalité technique exceptionnelles, caractérisée par sa touche tourbillonnante et sa palette de couleurs saturées. Mort à trente-sept ans, il ne vend qu\'un seul tableau de son vivant mais laisse plus de neuf cents toiles qui définissent le post-impressionnisme.', '1853', '1890'),
(35, 'Homer', 'Winslow', 'Américain', 'Winslow Homer est l\'un des plus grands peintres américains du XIXe siècle, maître de la peinture de la nature sauvage et de la mer. D\'abord illustrateur de presse pendant la guerre de Sécession, il se tourne ensuite vers des sujets de plein air — pêcheurs, marins, chasse, vie rurale — traités avec une rigueur et une économie de moyens qui font de lui un précurseur du réalisme américain moderne. Sa maîtrise de l\'aquarelle est considérée comme l\'une des plus grandes de toute l\'histoire de cette technique.', '1836', '1910');
INSERT INTO `oeuvres` (`id`, `titre`, `description`, `annee_creation`, `artiste_id`) VALUES
(1, 'La Joconde', 'Mona Lisa est l\'un des portraits les plus célèbres de la Renaissance italienne. Commencée à Florence au début du XVIe siècle et probablement retravaillée par Léonard de Vinci jusqu\'à la fin de sa vie, l\'œuvre illustre les recherches du peintre sur le sfumato, la psychologie du modèle et l\'intégration subtile de la figure dans un paysage atmosphérique. Son histoire muséale est également remarquable : entrée dans les collections royales françaises, puis conservée au Louvre, elle est devenue au XXe siècle un symbole mondial de la peinture occidentale.', '1503-1519', 25),
(2, 'La Nuit étoilée', 'Réalisée en 1889 pendant l\'internement volontaire de Vincent van Gogh à Saint-Rémy-de-Provence, La Nuit étoilée traduit moins une observation réaliste du ciel qu\'une vision intérieure fortement stylisée. Le village, les cyprès et les astres sont structurés par un mouvement de touches tourbillonnantes qui donne à la composition une intensité expressive exceptionnelle. L\'œuvre est aujourd\'hui considérée comme une synthèse majeure de la modernité picturale de Van Gogh, entre paysage, émotion et construction symbolique.', '1889', 34),
(3, 'Le Cri', 'Le Cri appartient à une série de compositions dans lesquelles Edvard Munch explore l\'angoisse moderne, la solitude et la fragilité psychique de l\'individu. Peinte dans le contexte du symbolisme fin-de-siècle, l\'œuvre représente une figure déformée traversée par une tension existentielle, tandis que le paysage lui-même semble vibrer sous l\'effet du malaise. Cette image est devenue l\'un des emblèmes de l\'expressionnisme naissant et de la représentation artistique de l\'anxiété contemporaine.', '1893', 8),
(4, 'La Jeune Fille à la perle', 'La Jeune Fille à la perle est généralement qualifiée de tronie, c\'est-à-dire une étude de physionomie ou de caractère, plutôt qu\'un portrait identifié. Vermeer y concentre son art sur la lumière, le modelé du visage, le contraste du fond sombre et l\'éclat de la perle, élément visuel central de la composition. L\'œuvre témoigne de la maîtrise technique de la peinture hollandaise du XVIIe siècle, mais aussi de la capacité de Vermeer à transformer une figure simple en présence silencieuse et énigmatique.', 'vers 1665', 22),
(5, 'La Naissance de Vénus', 'Commandée dans le contexte de la Florence médicéenne, La Naissance de Vénus s\'inscrit dans la redécouverte humaniste de l\'Antiquité. Botticelli représente la déesse arrivant sur le rivage, selon une iconographie inspirée des textes antiques et de la culture néoplatonicienne. Par son dessin linéaire, son rythme décoratif et son traitement idéalisé du corps, l\'œuvre constitue l\'un des sommets de la première Renaissance florentine et marque une étape importante dans le retour du nu mythologique dans la peinture occidentale.', 'vers 1485', 32),
(6, 'Les Ménines', 'Les Ménines est une œuvre capitale de la peinture baroque espagnole et de la réflexion sur le statut du peintre. Velázquez y représente l\'infante Marguerite entourée de sa suite, tout en se figurant lui-même au travail devant une grande toile. Le jeu complexe des regards, du miroir et de l\'espace pictural interroge la relation entre le modèle, le spectateur et la représentation. Conservée au Prado, l\'œuvre est souvent analysée comme une méditation magistrale sur la peinture, le pouvoir royal et la mise en scène de la cour.', '1656', 6),
(7, 'La Liberté guidant le peuple', 'Peinte à la suite des Trois Glorieuses de juillet 1830, La Liberté guidant le peuple associe événement historique récent et allégorie politique. Delacroix représente la Liberté sous les traits d\'une figure féminine entraînant le peuple parisien au combat, dans une composition dramatique où se mêlent réalisme, idéalisation et énergie romantique. L\'œuvre est devenue une image majeure de l\'imaginaire républicain français, bien que son sens politique ait été interprété différemment selon les époques.', '1830', 10),
(8, 'Le Déjeuner sur l\'herbe', 'Présenté au Salon des refusés en 1863, Le Déjeuner sur l\'herbe provoqua un scandale en raison de la présence d\'un nu féminin contemporain au sein d\'une scène de plein air avec des hommes habillés. Manet y rompt avec les conventions académiques du nu mythologique et revendique une peinture moderne, frontale et volontairement ambiguë. L\'œuvre occupe une place décisive dans l\'histoire de la modernité picturale, en annonçant les débats qui accompagneront l\'impressionnisme et la peinture indépendante.', '1863', 7),
(9, 'Impression, soleil levant', 'Impression, soleil levant représente le port du Havre dans une lumière brumeuse, avec une grande économie de moyens et une touche rapide. Exposée en 1874 lors de la première exposition du groupe impressionniste, l\'œuvre donna son nom au mouvement après une critique ironique de Louis Leroy. Elle constitue un jalon essentiel de la peinture moderne : le sujet y compte moins que la perception fugitive de la lumière, de l\'atmosphère et de la couleur.', '1872', 5),
(10, 'Les Tournesols', 'Les Tournesols appartient à la série réalisée par Van Gogh à Arles en 1888, au moment où l\'artiste prépare la Maison jaune pour accueillir Paul Gauguin. Le motif floral, apparemment simple, devient un laboratoire de couleur, de matière et de variation chromatique autour des jaunes. Cette série occupe une place centrale dans l\'identité artistique de Van Gogh : elle associe ambition décorative, intensité émotionnelle et affirmation d\'une peinture fondée sur l\'énergie de la touche.', '1888', 34),
(11, 'La Grande Vague de Kanagawa', 'La Grande Vague de Kanagawa est la première planche de la série Trente-six vues du mont Fuji. Hokusai y combine la tradition de l\'estampe japonaise ukiyo-e, une composition très dynamique et l\'usage du bleu de Prusse, pigment alors récemment diffusé au Japon. L\'image met en tension la puissance de la mer, la fragilité des embarcations et la permanence du mont Fuji à l\'arrière-plan. Sa diffusion internationale a profondément marqué le japonisme et l\'art européen du XIXe siècle.', 'vers 1831', 24),
(12, 'American Gothic', 'American Gothic fut peint par Grant Wood au début de la Grande Dépression et s\'impose comme l\'une des images les plus identifiables de l\'art américain. La composition associe un couple rural frontal, une maison de style néogothique et une austérité volontairement théâtrale. L\'œuvre a été interprétée tour à tour comme hommage, satire ou commentaire social sur l\'Amérique provinciale. Sa force tient précisément à cette ambiguïté, qui en a fait une icône culturelle largement réappropriée.', '1930', 14),
(13, 'Le Baiser', 'Le Baiser appartient à la période dorée de Gustav Klimt, marquée par l\'usage décoratif de l\'or, l\'influence des arts byzantins et l\'esthétique de la Sécession viennoise. Le couple enlacé se détache dans un espace presque abstrait où motifs géométriques, surface précieuse et symbolique érotique se combinent. L\'œuvre condense les recherches de Klimt sur l\'ornement, le désir et la fusion des corps, tout en demeurant l\'un des tableaux les plus célèbres de l\'art autrichien.', '1907-1908', 15),
(14, 'La Création d\'Adam', 'La Création d\'Adam est l\'un des épisodes centraux du plafond de la chapelle Sixtine, commandé à Michel-Ange par le pape Jules II. La fresque représente l\'instant précédant la transmission de la vie à Adam, selon une composition d\'une grande tension visuelle entre les deux mains presque jointes. Elle illustre la monumentalité du corps humain dans l\'art de la Haute Renaissance et la capacité de Michel-Ange à transformer un sujet théologique en image universelle de la création.', '1511-1512', 26),
(15, 'Le Radeau de la Méduse', 'Le Radeau de la Méduse prend pour sujet un fait divers politique majeur : le naufrage de la frégate Méduse en 1816 et l\'abandon d\'une partie de son équipage. Géricault mena une enquête approfondie, étudia des cadavres et construisit une composition monumentale où le désespoir collectif est organisé autour d\'un mouvement ascendant vers l\'espoir. Par son réalisme dramatique et son engagement implicite, l\'œuvre marque une rupture avec l\'héroïsme néoclassique et annonce la sensibilité romantique.', '1818-1819', 33),
(16, 'La Laitière', 'La Laitière représente une servante versant du lait dans un intérieur sobre, baigné par une lumière latérale caractéristique de Vermeer. La scène domestique, d\'apparence ordinaire, est construite avec une grande précision spatiale et une attention exceptionnelle aux matières : pain, céramique, tissu et mur enduit. L\'œuvre témoigne de l\'intérêt de la peinture hollandaise du Siècle d\'or pour la vie quotidienne, tout en élevant un geste simple au rang d\'image méditative.', 'vers 1658', 22),
(17, 'Les Époux Arnolfini', 'Les Époux Arnolfini est un chef-d\'œuvre de la peinture flamande du XVe siècle, célèbre pour son rendu minutieux des matières, son miroir convexe et sa densité symbolique. La scène a longtemps été interprétée comme une représentation de mariage ou de contrat social, même si les lectures contemporaines restent nuancées. Par son usage virtuose de la peinture à l\'huile et sa précision optique, l\'œuvre illustre le raffinement technique et intellectuel des anciens Pays-Bas bourguignons.', '1434', 19),
(18, 'Le Serment des Horaces', 'Le Serment des Horaces fut peint par Jacques-Louis David à Rome peu avant la Révolution française et s\'imposa comme un manifeste du néoclassicisme. Inspirée de l\'histoire romaine, la scène exalte le devoir civique, le sacrifice familial et la rigueur morale à travers une composition claire, architecturée et volontairement austère. L\'œuvre annonce le rôle politique que la peinture d\'histoire jouera dans la France de la fin du XVIIIe siècle.', '1784', 18),
(19, 'La Mort de Marat', 'La Mort de Marat fut réalisée quelques mois après l\'assassinat du révolutionnaire Jean-Paul Marat par Charlotte Corday. David transforme un événement politique immédiat en image de martyre républicain, réduisant la scène à quelques éléments : le corps, la baignoire, la lettre et la lumière. Par son dépouillement formel et sa puissance de propagande, l\'œuvre constitue l\'un des exemples les plus saisissants de l\'art engagé pendant la Révolution française.', '1793', 18),
(20, 'Le Jardin des délices', 'Le Jardin des délices est un triptyque énigmatique de Jérôme Bosch, souvent interprété comme une méditation morale sur la création, le désir, le péché et la damnation. Sa profusion de figures hybrides, d\'architectures fantastiques et de scènes symboliques en fait l\'une des œuvres les plus complexes de la fin du Moyen Âge européen. Conservé au Prado, le tableau reste un support privilégié pour étudier l\'imaginaire religieux, la satire morale et la richesse visuelle de la peinture nordique.', 'vers 1490-1500', 20),
(21, 'Nighthawks', 'Nighthawks est l\'œuvre la plus célèbre d\'Edward Hopper, peintre américain du réalisme urbain. Elle représente quatre personnages attablés dans un diner illuminé au coin d\'une rue new-yorkaise déserte en pleine nuit. L\'absence de porte visible, le silence des silhouettes et le contraste brutal entre l\'intérieur éclairé et l\'extérieur sombre créent une atmosphère de solitude et d\'aliénation caractéristique de l\'œuvre de Hopper. Peinte peu après l\'entrée en guerre des États-Unis, l\'image est devenue un symbole de l\'Amérique moderne et de l\'isolement de l\'individu dans la ville.', '1942', 9),
(22, 'Temple Antique', 'Giovanni Paolo Panini est le maître incontesté du capriccio architectural et de la représentation de l\'Antiquité romaine. Ses compositions de temples antiques assemblent ruines, colonnes et figures dans des paysages idéalisés qui répondent au goût du Grand Tour européen. Ces œuvres témoignent de la fascination du XVIIIe siècle pour Rome, à la fois comme lieu de mémoire et comme source d\'inspiration esthétique. Panini a profondément influencé la tradition du paysage architectural classique en Europe.', 'vers 1735', 13),
(23, 'Le Voyageur contemplant une mer de nuages', 'Der Wanderer über dem Nebelmeer est l\'une des œuvres emblématiques du romantisme allemand. Un homme de dos, debout sur un rocher, contemple un paysage montagneux enveloppé de brumes et de nuages. La figure solitaire de dos — procédé récurrent chez Friedrich — invite le spectateur à s\'identifier à ce regard perdu dans l\'infini, entre sublime naturel et introspection mélancolique. L\'œuvre condense les aspirations romantiques : la primauté de l\'émotion, la spiritualité du paysage et la confrontation de l\'individu à l\'immensité du monde.', 'vers 1818', 4),
(24, 'La Mort et le Fossoyeur', 'La Mort et le Fossoyeur est une œuvre majeure du symbolisme fin-de-siècle, réalisée par le peintre suisse Carlos Schwabe. Elle représente la Mort sous les traits d\'un ange ailé aux ailes de neige, tenant fermement le vieux fossoyeur qui s\'effondre. La composition associe la délicatesse décorative du style Art nouveau à une iconographie de la mort à la fois sereine et inexorable. Le contraste entre la blancheur de la Mort et la misère terrestre du vieil homme évoque une méditation poétique sur la condition humaine et le passage vers l\'au-delà.', '1895', 3),
(25, 'L\'Île des morts', 'L\'Île des morts est la plus célèbre des cinq versions peintes par Arnold Böcklin entre 1880 et 1886. Elle représente une île rocheuse aux cyprès noirs entourée d\'une mer calme, vers laquelle une barque transporte un cercueil accompagné d\'une figure blanche — image de Charon et du voyage des âmes. La composition silencieuse et monumentale, entre symbolisme et vision onirique, a exercé une fascination considérable sur les artistes et les écrivains de la fin du XIXe siècle. Böcklin refusa toujours d\'en dévoiler la signification précise.', '1883', 2),
(26, 'The Burning of the Houses of Parliament', 'Turner assista en personne à l\'incendie du Parlement de Westminster en octobre 1834 et réalisa deux grandes toiles de l\'événement. Celle du Cleveland Museum of Art, peinte en 1835, dissout le bâtiment en flammes dans un tourbillon de lumières orangées se reflétant sur la Tamise. Turner y pousse à l\'extrême sa technique du vortex lumineux, faisant du désastre architectural une expérience quasi abstraite de couleur et de feu. Cette œuvre annonce le tournant le plus radical de son art vers la dissolution des formes dans la lumière.', '1835', 23),
(27, 'Sunset Near Overschie', 'Johan Barthold Jongkind, peintre néerlando-français considéré comme un précurseur de l\'impressionnisme, excelle dans la représentation de l\'atmosphère lumineuse des paysages hollandais au crépuscule. Sunset Near Overschie illustre sa sensibilité particulière aux effets de lumière rasante sur les eaux et les ciels nuageux des Pays-Bas. Sa touche libre et sa palette lumineuse ont directement influencé Monet, qui le reconnaissait comme l\'un de ses maîtres. L\'œuvre témoigne du passage entre la peinture de paysage romantique et la modernité impressionniste.', '1855', 21),
(28, 'The Fog Warning', 'The Fog Warning est l\'une des œuvres majeures de Winslow Homer consacrées à la vie des pêcheurs de la côte atlantique. Elle représente un pêcheur seul dans une doris, avec deux flétans à bord, scrutant l\'horizon où le brouillard menace de couper le chemin du retour vers le bateau-mère. La mer grise et houleuse, l\'isolement de l\'homme face aux éléments et l\'imminence du danger confèrent à la scène une intensité dramatique retenue. Homer y exprime la dignité des travailleurs de la mer confrontés aux forces de la nature.', '1885', 35),
(29, 'Les Amants', 'Les Amants de René Magritte représente deux personnages qui s\'embrassent, la tête enveloppée chacun dans un tissu blanc opaque. Ce voile, qui empêche tout contact réel entre les deux visages, transforme l\'acte du baiser en geste aveugle et impossible. Magritte interroge ainsi les thèmes de la communication, du désir et de l\'identité cachée, fondamentaux dans son œuvre surréaliste. Le tableau a été associé à la mort traumatisante de sa mère, retrouvée noyée la tête couverte de sa chemise de nuit.', '1928', 30),
(30, 'Guernica', 'Guernica fut réalisée par Picasso en réponse au bombardement de la ville basque de Guernica par l\'aviation nazie et fasciste en avril 1937. Grande composition en gris, noir et blanc, l\'œuvre condense les figures du taureau, du cheval blessé, de la femme au bébé mort et des corps éclatés en un cri d\'horreur contre la guerre. Exposée pendant des années à New York comme symbole de résistance, elle revint en Espagne après la mort de Franco. Guernica est aujourd\'hui l\'œuvre anti-guerre la plus universellement connue du XXe siècle.', '1937', 27),
(31, 'Les Demoiselles d\'Avignon', 'Les Demoiselles d\'Avignon est considérée comme l\'œuvre fondatrice du cubisme et l\'un des tournants décisifs de l\'histoire de l\'art moderne. Picasso y représente cinq figures féminines aux corps fragmentés, combinant influences de l\'art ibérique et des masques africains. La rupture avec la perspective traditionnelle, la déformation des corps et la confrontation directe du regard des personnages avec le spectateur font de cette toile une provocation formelle radicale. L\'œuvre, d\'abord tenue secrète, fut révélée au public en 1916 et changea durablement les conventions de la représentation.', '1907', 27),
(32, 'Le Grand Masturbateur', 'Le Grand Masturbateur est une œuvre clé de la période surréaliste de Salvador Dalí, réalisée l\'année de sa rencontre avec Gala. La composition est dominée par une forme molle et organique inspirée d\'un rocher du Cap de Creus, surmontée d\'un visage aux yeux clos aux longs cils. De cette forme émergent des figures érotiques, des insectes et des éléments biomorphiques qui peuplent un paysage onirique. L\'œuvre traduit les angoisses et les désirs de Dalí, sa fascination pour la psychanalyse freudienne et son rapport trouble à la sexualité.', '1929', 31),
(33, 'La Persistance de la mémoire', 'La Persistance de la mémoire est la toile la plus célèbre de Salvador Dalí et l\'une des images emblématiques du surréalisme. Ses montres molles et fondantes, disposées sur un paysage désolé qui rappelle la côte de Catalogne, remettent en question la rigidité du temps et la réalité de la perception. Dalí affirma avoir eu l\'idée en contemplant un camembert fondant. L\'œuvre illustre la méthode paranoïaque-critique qu\'il développait alors, consistant à projeter des visions irrationnelles dans des représentations peintes avec une précision photographique.', '1931', 31),
(34, 'Massacre en Corée', 'Massacre en Corée fut peint par Picasso en janvier 1951 en réponse aux violences commises lors de la guerre de Corée, notamment les massacres de civils. La composition en deux groupes — soldats mécaniques armés d\'un côté, femmes et enfants nus de l\'autre — s\'inspire explicitement du Tres de Mayo de Goya et des Fusillades de la princesse d\'Asturies de Manet. L\'œuvre, ouvertement politique et militante, fut diversement accueillie, mais incarne l\'engagement de Picasso contre la guerre et les violences impérialistes.', '1951', 27),
(35, 'Le Fils de l\'homme', 'Le Fils de l\'homme est l\'un des autoportraits les plus connus de René Magritte, dans lequel le peintre se représente en homme au chapeau melon dont le visage est masqué par une pomme verte flottant devant lui. L\'œuvre joue sur le désir de voir ce qui est caché par ce qui est visible, thème central de la réflexion surréaliste de Magritte sur la représentation et le mystère de l\'identité. Magritte a décrit lui-même l\'œuvre comme une illustration du conflit entre ce qui est visible et ce qui est dissimulé.', '1964', 30),
(36, 'Golconde', 'Golconde représente une pluie d\'hommes en manteau et chapeau melon tombant — ou montant — sur fond de façades bourgeoises belges. Cette répétition sérielle de la figure masculine anonyme, emblème de Magritte lui-même, interroge la notion de singularité dans la masse, d\'individualité et d\'invisibilité sociale. Le titre renvoie à Golconde, ancienne ville de l\'Inde réputée pour ses richesses, laissant entendre une ironie sur l\'abondance d\'hommes interchangeables. L\'œuvre est l\'une des plus célèbres du surréalisme belge.', '1953', 30),
(37, 'Le Trois Mai 1808', 'Le Tres de Mayo 1808 fut peint par Goya six ans après les événements pour commémorer les résistants madrilènes fusillés par les troupes napoléoniennes. La composition oppose la masse mécanique et anonyme des soldats aux civils espagnols regroupés, au centre desquels un homme en blanc aux bras levés incarne à la fois la victime et le martyr. Par son réalisme brutal et son refus de toute gloire héroïque, l\'œuvre bouleverse les conventions de la peinture d\'histoire et influence directement Manet et Picasso. C\'est l\'un des premiers grands tableaux politiques de la peinture moderne.', '1814', 11),
(38, 'Ceci n\'est pas une pipe', 'La Trahison des images, connue sous le titre Ceci n\'est pas une pipe, est l\'œuvre la plus célèbre de René Magritte sur le rapport entre les mots, les images et la réalité. Sous la représentation peinte d\'une pipe, l\'inscription « Ceci n\'est pas une pipe » rappelle que l\'image d\'une chose n\'est pas la chose elle-même. Cette réflexion sur la nature du signe pictural et du langage a été théorisée par Michel Foucault dans un essai célèbre. L\'œuvre demeure l\'une des plus puissantes illustrations philosophiques produites par le surréalisme.', '1929', 30),
(39, 'Campbell\'s Soup Cans', 'Campbell\'s Soup Cans est l\'œuvre qui lança la notoriété d\'Andy Warhol et devint un manifeste du Pop Art américain. La série de 32 toiles représente chacune une variété différente de soupe en boîte Campbell, reproduite avec une précision quasi mécanique qui efface toute trace de geste artistique. En choisissant un produit de grande consommation comme sujet pictural, Warhol interroge la valeur de l\'art, la culture de masse et la société américaine de l\'abondance. L\'œuvre renverse les hiérarchies artistiques traditionnelles en élevant l\'objet banal au rang d\'icône.', '1962', 1),
(40, 'Marilyn Diptych', 'Le Diptyque Marilyn fut réalisé par Andy Warhol peu après la mort de Marilyn Monroe en août 1962. Il associe 50 images sérigraphiées du visage de l\'actrice, en couleurs vives d\'un côté et en noir et blanc de l\'autre, évoquant la dégradation progressive de l\'image et de l\'idole. Warhol transforme le portrait d\'une star en icône sacrée et commentaire sur la célébrité, la mort et la reproductibilité à l\'ère des médias de masse. La référence au format du diptyque religieux n\'est pas fortuite.', '1962', 1),
(41, 'Eight Elvises', 'Eight Elvises est l\'une des grandes sérigraphies d\'Andy Warhol consacrées à la figure d\'Elvis Presley, roi du rock\'n\'roll devenu icône de la culture populaire américaine. La répétition en série de la même image d\'Elvis en cow-boy dégainé, sur fond argenté, démultiplie la star jusqu\'à l\'abstraction. L\'effet de sérigraphie décalée, avec ses zones floues et ses écarts chromatiques, traduit la dissolution de l\'individu dans sa propre image médiatique. L\'œuvre est l\'une des plus précieuses du marché de l\'art contemporain.', '1963', 1),
(42, 'Femme assise près d\'une fenêtre', 'Femme assise près d\'une fenêtre appartient à la série de portraits de Marie-Thérèse Walter que Picasso réalisa en 1932, considérée comme l\'un des sommets de son œuvre. Les formes rondes, les couleurs vives et l\'atmosphère lumineuse de ces toiles reflètent la passion de Picasso pour sa jeune maîtresse, qu\'il représente dans une plénitude sensuelle et presque sculpturale. La synthèse entre cubisme et classicisme, le traitement du visage vu de face et de profil simultanément et la richesse chromatique font de ces portraits des chefs-d\'œuvre de la modernité.', '1932', 27),
(43, 'Autoportrait à l\'oreille bandée', 'L\'Autoportrait à l\'oreille bandée fut peint par Van Gogh quelques semaines après l\'épisode au cours duquel il se trancha le lobe de l\'oreille gauche, en décembre 1888 à Arles, suite à une violente dispute avec Paul Gauguin. Le peintre se représente de face, bonnet de fourrure sur la tête, oreille gauche bandée, cigarette à la bouche, devant une toile et un tissu japonais. Le regard calme et déterminé contraste avec la violence récente de l\'incident. C\'est l\'un des autoportraits les plus poignants et les plus connus de l\'histoire de l\'art.', '1889', 34),
(44, 'Terrasse du café le soir', 'Terrasse du café le soir représente la terrasse du café qui se trouvait place du Forum à Arles, illuminée la nuit sous un ciel étoilé. Peinte en septembre 1888, l\'œuvre est remarquable par l\'absence de noir : Van Gogh obtient la nuit par la seule opposition des jaunes intenses de la lumière artificielle et du bleu profond du ciel. C\'est la première toile dans laquelle il intègre les étoiles directement dans la composition. Elle annonce La Nuit étoilée et illustre la recherche de Van Gogh sur la peinture nocturne en couleurs.', '1888', 34),
(45, 'Champ de blé aux corbeaux', 'Champ de blé aux corbeaux est l\'une des dernières toiles peintes par Van Gogh à Auvers-sur-Oise, quelques semaines avant sa mort. Un ciel d\'orage violacé s\'ouvre sur un champ de blé agité, tandis qu\'un vol de corbeaux noirs traverse la composition dans un mouvement menaçant. Les trois chemins qui s\'enfoncent dans le tableau ne mènent nulle part, accentuant le sentiment d\'angoisse et d\'impasse. Longtemps considérée comme le dernier tableau de Van Gogh, l\'œuvre reste une image bouleversante de son état d\'esprit final.', '1890', 34),
(46, 'La Chambre à Arles', 'La Chambre à Arles représente la chambre à coucher de Van Gogh dans la Maison Jaune d\'Arles, qu\'il occupa de mai 1888 à mai 1889. Van Gogh réalisa trois versions de cette composition, destinées à donner l\'impression de repos et de sommeil. La perspective volontairement faussée, les couleurs vives des murs bleus, du lit orangé et du sol vert, et la simplicité des objets traduisent à la fois son aspiration à la sérénité et la tension que dissimule cet intérieur apparemment paisible. C\'est l\'une des œuvres les plus aimées et les plus reproduites de Van Gogh.', '1888', 34),
(47, 'Le Moulin de la Galette', 'Bal du moulin de la Galette est considéré comme l\'un des chefs-d\'œuvre de l\'impressionnisme et de la peinture française du XIXe siècle. Renoir y représente une foule de Parisiens réunis un dimanche après-midi dans le célèbre bal de Montmartre, sous une lumière tachetée de soleil et d\'ombre filtrée par les feuillages. La composition vibrante, l\'atmosphère festive et la fluidité des silhouettes font de ce tableau une célébration de la vie moderne et populaire. La toile fut exposée à la troisième exposition impressionniste en 1877.', '1876', 28),
(48, 'Paris Street, Rainy Day', 'Paris Street, Rainy Day est le tableau le plus célèbre de Gustave Caillebotte et l\'une des représentations les plus marquantes du Paris haussmannien. La composition montre un carrefour parisien sous la pluie, peuplé de bourgeois aux parapluies, avec une rigueur de cadrage et une perspective presque photographique. Caillebotte intègre les codes de l\'impressionnisme tout en maintenant une précision réaliste qui lui est propre. L\'œuvre capte le caractère moderne, anonyme et fluide de la vie urbaine dans la capitale rénovée par le baron Haussmann.', '1877', 16),
(49, 'Le Déjeuner des canotiers', 'Le Déjeuner des canotiers représente un groupe d\'amis de Renoir attablés sur la terrasse de la Maison Fournaise à Chatou, au bord de la Seine. La lumière qui filtre à travers la treille, les visages animés, les verres et les fruits sur la table composent un hymne à la convivialité et aux plaisirs de la vie moderne. Parmi les personnages figurent plusieurs proches du peintre, dont Aline Charigot, sa future femme. Cette toile joyeuse et solaire est souvent considérée comme l\'une des dernières grandes compositions impressionnistes de Renoir avant son virage vers un classicisme plus sévère.', '1881', 28),
(50, 'The Singing Butler', 'The Singing Butler est la peinture la plus célèbre du peintre écossais Jack Vettriano et l\'une des images les plus reproduites de la peinture britannique contemporaine. Elle représente un couple élégant dansant sur une plage balayée par le vent, sous la surveillance souriante d\'un majordome tenant un parapluie et d\'une domestique. L\'ambiance rétro, la romantisme discret et l\'élégance mélancolique du tableau en ont fait un phénomène de culture populaire au Royaume-Uni. Vettriano, autodidacte, reste une figure atypique dans le paysage de l\'art contemporain.', '1992', 17),
(51, 'La Gare Saint-Lazare', 'La Gare Saint-Lazare est l\'une des séries les plus ambitieuses de Monet, qui s\'installa en 1877 dans la gare parisienne pour en peindre douze toiles différentes. Il y capture la vapeur des locomotives, la lumière filtrée par la verrière et l\'animation des quais dans une palette de gris, de bleus et de roses. Cette série marque une étape décisive dans la méthode sérielle de Monet, qui cherche à saisir les variations d\'un même motif sous différentes conditions lumineuses — méthode qu\'il développera avec les Meules, les Cathédrales de Rouen et les Nymphéas.', '1877', 5),
(52, 'La Tour des chevaux bleus', 'La Tour des chevaux bleus est l\'une des œuvres majeures de l\'expressionnisme allemand et du groupe Der Blaue Reiter (Le Cavalier bleu), co-fondé par Franz Marc et Wassily Kandinsky. Elle représente quatre chevaux bleus dressés en colonne, dont les corps se fondent et s\'entrelacent dans un paysage aux couleurs saturées. Pour Marc, le bleu symbolisait la spiritualité masculine et la profondeur ; le cheval incarnait la pureté et la beauté primordiale. L\'œuvre fut saisie par les nazis en 1937 comme art dégénéré et a depuis disparu.', '1913', 12),
(53, 'Les Coquelicots', 'Les Coquelicots est l\'une des œuvres les plus populaires de Claude Monet et de l\'impressionnisme. Elle représente sa femme Camille et son fils Jean dans un champ de coquelicots rouges près d\'Argenteuil, sous un ciel d\'été lumineux. La composition en diagonale, les taches rouges des fleurs et la légèreté de la touche impressionniste donnent à l\'œuvre une vivacité et une fraîcheur exceptionnelles. Présentée à la première exposition impressionniste de 1874, elle incarne parfaitement les ambitions du groupe : capter le moment fugitif, la lumière naturelle et la vie moderne.', '1873', 5),
(54, 'Le Christ dans la tempête sur la mer de Galilée', 'Le Christ dans la tempête sur la mer de Galilée est la seule peinture de marine connue de Rembrandt, et l\'une des œuvres les plus célèbres de sa carrière. Elle représente l\'épisode évangélique où le Christ calme la tempête qui menace de couler la barque des disciples. La composition dramatique, avec la mer déchaînée, les figures en lutte contre les éléments et la lumière surnaturelle qui émane du Christ, illustre la maîtrise baroque de Rembrandt. L\'œuvre fut volée en 1990 lors du plus grand cambriolage d\'art de l\'histoire et n\'a jamais été retrouvée.', '1633', 29),
(55, 'Saturne dévorant un de ses fils', 'Saturne dévorant un de ses fils appartient aux Peintures noires, ensemble de fresques que Goya réalisa directement sur les murs de sa maison — la Quinta del Sordo — entre 1819 et 1823, à la fin de sa vie. L\'image monumentale et terrifiante du dieu dévorant son enfant, les yeux écarquillés dans un regard de folie, est traitée avec une violence et une liberté formelle sans précédent dans la peinture occidentale. Goya y exprime ses hantises les plus intimes, sa vision de la brutalité du pouvoir et son angoisse devant la mort. L\'œuvre est considérée comme l\'un des précurseurs de l\'expressionnisme et de l\'art moderne.', '1820-1823', 11)
